import { useState, useRef, useEffect } from "react"; // Applying Inter font update

// ── Session ID ────────────────────────────────────────────────────────────────
const SESSION_KEY = "ai_support_session_id";
function makeSessionId(): string {
  const id = crypto.randomUUID();
  sessionStorage.setItem(SESSION_KEY, id);
  return id;
}
function getOrCreateSessionId(): string {
  return sessionStorage.getItem(SESSION_KEY) ?? makeSessionId();
}

// ── Types ─────────────────────────────────────────────────────────────────────
interface ChatMessage {
  id: number;
  role: "user" | "bot";
  text: string;
  source?: string | null;
  ts: number; // Unix ms timestamp
}

// ── Relative timestamp ────────────────────────────────────────────────────────
function useRelativeTime(ts: number): string {
  const [label, setLabel] = useState(() => getRelLabel(ts));
  useEffect(() => {
    setLabel(getRelLabel(ts));
    const iv = setInterval(() => setLabel(getRelLabel(ts)), 10_000);
    return () => clearInterval(iv);
  }, [ts]);
  return label;
}
function getRelLabel(ts: number): string {
  const diff = Math.floor((Date.now() - ts) / 1000);
  if (diff < 60) return "Just Now";
  if (diff < 3600) return `${Math.floor(diff / 60)} min ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)} hr ago`;
  return `${Math.floor(diff / 86400)} day ago`;
}
interface Settings {
  faqs: boolean;
  leads: boolean;
}

